// Filter topics for next 14 days
const today = new Date();
const dateStart = new Date(today);
const dateEnd = new Date(today);
dateEnd.setDate(dateEnd.getDate() + 14);

const allEntries = $input.all();
const weekEntries = [];

for (const entry of allEntries) {
  const props = entry.json.properties;
  const dateProp = props?.Date?.date;

  if (!dateProp || !dateProp.start) continue;

  const entryDate = new Date(dateProp.start);
  const mappedDate = new Date(today.getFullYear(), entryDate.getMonth(), entryDate.getDate());

  if (mappedDate >= dateStart && mappedDate <= dateEnd) {
    const name = props?.Name?.title?.map(t => t.plain_text).join('') || '';
    const types = props?.['Email Type']?.multi_select?.map(s => s.name) || [];

    weekEntries.push({
      name: name,
      date: mappedDate.toISOString().split('T')[0],
      types: types,
      pageId: entry.json.id
    });
  }
}

weekEntries.sort((a, b) => new Date(a.date) - new Date(b.date));

return weekEntries.map(entry => ({
  json: entry
}));

const records = $input.all();

const clients = records.map(record => ({
  id: record.json.id,
  firmenname: record.json.fields?.Firmenname || '',
  klaviyoKey: record.json.fields?.['Klaviyo API Key'] || '',
  website: record.json.fields?.Website || '',
  branche: record.json.fields?.Branche || '',
  tonalitaet: record.json.fields?.Tonalität || '',
  emailFrom: record.json.fields?.['E-Mail Rechnungen'] || 'hello@adsdrop.de'
})).filter(c => c.klaviyoKey);

return clients.map(client => ({
  json: { type: 'client', data: client }
}));

// Mark topics with type
const topics = $input.all().map(item => ({
  json: { type: 'topic', data: item.json }
}));

return topics;

const items = $input.all();

// Separate topics and clients
const topics = items
  .filter(i => i.json.type === 'topic')
  .map(i => i.json.data);

const clients = items
  .filter(i => i.json.type === 'client')
  .map(i => i.json.data);

if (topics.length === 0 || clients.length === 0) {
  throw new Error(`Missing data: ${topics.length} topics, ${clients.length} clients`);
}

// Create all combinations
const combinations = [];
for (const client of clients) {
  for (const topic of topics) {
    combinations.push({
      json: {
        topic: topic,
        client: client
      }
    });
  }
}

return combinations;

