const item = $input.first().json;
const client = item.client;

try {
  const response = await $httpRequest({
    method: 'GET',
    url: 'https://a.klaviyo.com/api/lists',
    headers: {
      'Authorization': `Klaviyo-API-Key ${client.klaviyoKey}`,
      'revision': '2024-10-15'
    }
  });

  const lists = response.body?.data || [];
  let targetList = lists[0]?.id;

  for (const list of lists) {
    const name = list.attributes?.name?.toLowerCase() || '';
    if (name.includes('newsletter') || name.includes('main') || name.includes('all')) {
      targetList = list.id;
      break;
    }
  }

  return [{
    json: {
      ...item,
      targetList: targetList
    }
  }];
} catch (error) {
  return [{
    json: {
      ...item,
      targetList: null,
      listError: error.message
    }
  }];
}

const item = $input.first().json;
const client = item.client;
const topic = item.topic;
const analysis = item.analysis;
const subject = item.subject;
const targetList = item.targetList;

// Calculate send date
const topicDate = topic.date;
const today = new Date();
let sendDate;

if (topicDate) {
  const topicDt = new Date(topicDate);
  if (topicDt < today) {
    sendDate = new Date(topicDt);
    sendDate.setDate(sendDate.getDate() + 7);
  } else {
    sendDate = topicDt;
  }
} else {
  sendDate = new Date(today);
  sendDate.setDate(sendDate.getDate() + 1);
}

const sendDatetime = sendDate.toISOString().split('T')[0] + 'T09:00:00.000Z';

const campaignData = {
  data: {
    type: 'campaign',
    attributes: {
      name: subject,
      audiences: { included: targetList ? [targetList] : [] },
      send_strategy: {
        method: 'static',
        options_static: { datetime: sendDatetime }
      },
      'campaign-messages': {
        data: [{
          type: 'campaign-message',
          attributes: {
            channel: 'email',
            label: subject.slice(0, 50),
            content: {
              subject: subject,
              preview_text: analysis.previewText
            }
          }
        }]
      }
    }
  }
};

try {
  const response = await $httpRequest({
    method: 'POST',
    url: 'https://a.klaviyo.com/api/campaigns',
    headers: {
      'Authorization': `Klaviyo-API-Key ${client.klaviyoKey}`,
      'revision': '2024-10-15',
      'Content-Type': 'application/json'
    },
    body: campaignData
  });

  return [{
    json: {
      client: client,
      topic: topic,
      subject: subject,
      campaignId: response.body?.data?.id,
      status: 'Created',
      sendDate: sendDate.toISOString().split('T')[0]
    }
  }];
} catch (error) {
  return [{
    json: {
      client: client,
      topic: topic,
      subject: subject,
      campaignId: null,
      status: 'Failed',
      error: error.message
    }
  }];
}

const results = $input.all();

const campaigns = results.map(r => r.json);
const successful = campaigns.filter(c => c.campaignId).length;
const failed = campaigns.length - successful;

const clientSummary = {};
for (const camp of campaigns) {
  if (!clientSummary[camp.client?.firmenname]) {
    clientSummary[camp.client?.firmenname] = 0; }
  if (camp.campaignId) clientSummary[camp.client?.firmenname]++;
}

return [{
  json: {
    successful,
    failed,
    total: campaigns.length,
    campaigns,
    clientSummary,
    reportDate: new Date().toLocaleDateString('de-DE')
  }
}];

